        if not isinstance(c, dict):
            continue
        pub=c.get('publication_number')
        if pub in uc_pub_to_subclass:
            sc=uc_pub_to_subclass[pub]
            pairs.add((assignee, sc))
            subclasses.add(sc)

print('__RESULT__:')
