    m = re.search(r'pub\. number\s+([A-Z]{2}-\d{7,}-[A-Z]\d?)', pi)
    if not m:
        m = re.search(r'publication number\s+([A-Z]{2}-\d{7,}-[A-Z]\d?)', pi)
    pub = m.group(1) if m else None
    cpc_raw = r.get('cpc')
    primary = None
